package main

import (
	"context"
	"fmt"
	"net/http"
	"net/http/pprof"
	"os"
	"sync/atomic"
	"time"

	"aps_los_vtiger/config"
	"aps_los_vtiger/internal/adapter"
	"aps_los_vtiger/internal/adapter/metric"
	"aps_los_vtiger/internal/health"
	"aps_los_vtiger/internal/helper"
	"aps_los_vtiger/internal/repository"
	"aps_los_vtiger/internal/subscriber"
	"aps_los_vtiger/internal/usecase"

	"go.elastic.co/apm/v2"
	"go.uber.org/fx"
	"go.uber.org/fx/fxevent"
	"go.uber.org/zap"
)

type httpServerDeps struct {
	fx.In

	Lifecycle     fx.Lifecycle
	Logger        *zap.Logger
	Config        *config.Config
	HealthChecker *health.Checker
}

var (
	// processedTotal is total request had been processed
	// use atomic operations for safe thread
	processedTotal uint64
)

// gatherCustomMetrics is function APM agent  will call frequently to collect metrics
func gatherCustomMetrics(ctx context.Context, metrics *apm.Metrics) error {
	// add metric for total request had been processed
	// It is a sequence value
	metrics.Add("aps_los_vtiger_processed_total", // name of metric
		[]apm.MetricLabel{{Name: "type", Value: "api"}}, // set label
		float64(atomic.LoadUint64(&processedTotal)),     // set current value metric
	)
	metrics.Add("aps_los_vtiger_active_grpc_cfappdb_sessions",
		[]apm.MetricLabel{{Name: "type", Value: "cfappdb_grpc_connection"}},
		float64(metric.ActiveGrpcCfAppDb),
	)
	// we can also add others metric more
	return nil
}

// newHTTPServer wires up an http.Server on cfg.HttpAddress with health
// check endpoints and pprof routes registered on a fresh ServeMux.
// If cfg.HttpAddress is empty, the server is not started.
func newHTTPServer(deps httpServerDeps) *http.Server {
	mux := http.NewServeMux()
	mux.Handle("/healthz", deps.HealthChecker.LivenessHandler())
	mux.Handle("/readyz", deps.HealthChecker.ReadinessHandler())
	mux.Handle("/startupz", deps.HealthChecker.StartupHandler())

	// pprof endpoints — exposed under /debug/pprof/* for runtime profiling
	mux.HandleFunc("/debug/pprof/", pprof.Index)
	mux.HandleFunc("/debug/pprof/cmdline", pprof.Cmdline)
	mux.HandleFunc("/debug/pprof/profile", pprof.Profile)
	mux.HandleFunc("/debug/pprof/symbol", pprof.Symbol)
	mux.HandleFunc("/debug/pprof/trace", pprof.Trace)

	srv := &http.Server{
		Addr:              fmt.Sprintf(":%s", deps.Config.Base.HttpAddress),
		Handler:           mux,
		ReadHeaderTimeout: 5 * time.Second,
	}

	deps.Lifecycle.Append(fx.Hook{
		OnStart: func(_ context.Context) error {
			deps.Logger.Info("Starting health HTTP server", zap.String("addr", srv.Addr))
			go func() {
				if err := srv.ListenAndServe(); err != nil && err != http.ErrServerClosed {
					deps.Logger.Error("Health HTTP server failed", zap.Error(err))
				}
			}()
			deps.HealthChecker.SetStartupComplete(true)
			deps.HealthChecker.SetReady(true)
			deps.Logger.Info("Health check: service marked as ready")
			return nil
		},
		OnStop: func(ctx context.Context) error {
			deps.HealthChecker.SetReady(false)
			deps.Logger.Info("Health check: service marked as not ready (shutting down)")
			return srv.Shutdown(ctx)
		},
	})
	return srv
}

func main() {
	// registe function collect metric with Elastic APM default Tracer.
	if tr := apm.DefaultTracer(); tr != nil && tr.Recording() {
		tr.RegisterMetricsGatherer(apm.GatherMetricsFunc(gatherCustomMetrics))
		zap.L().Info("Custom metrics gatherer registered with Elastic APM.")
	}

	fx.New(
		fx.WithLogger(func(log *zap.Logger) fxevent.Logger {
			return &fxevent.ConsoleLogger{W: os.Stderr}
		}),
		helper.Provide(),
		adapter.Provide(),
		usecase.Provide(),
		repository.Provide(),
		subscriber.Provide(),
		fx.Provide(
			config.Load,
			health.NewChecker,
			newHTTPServer,
		),
		fx.Invoke(
			func(*http.Server) {},
		),
		fx.Invoke(
			subscriber.Start,
		),
	).Run()
}

