package adapter

import (
	"aps_los_vtiger/config"
	"aps_los_vtiger/internal/adapter/metric"
	"aps_los_vtiger/internal/health"
	"context"
	"esb-go-libs/util"
	poolClient "fec_pool_service/cmd/client"
	"fmt"

	"esb-go-libs/dbadapter"

	"go.uber.org/fx"
	"go.uber.org/zap"
)

func newCfAppDbPoolClient(lc fx.Lifecycle, cfg *config.Config, checker *health.Checker) (poolClient.IClientPoolService, error) {
	cfAppDbGrpcAddress := fmt.Sprintf("%s:%s", cfg.CfAppDbClient.Host, cfg.CfAppDbClient.Port)
	client, err := poolClient.NewPoolServerClient(cfAppDbGrpcAddress)
	if err != nil {
		zap.L().Error("Failed to create CfAppDb grpc client", zap.Error(err))
		return nil, err
	}
	metric.IncrementActiveGrpcCfAppDb()
	checker.SetGRPCConn(client.GetConn(), cfAppDbGrpcAddress)
	lc.Append(fx.Hook{
		OnStop: func(ctx context.Context) error {
			client.Close()
			metric.DecrementActiveGrpcCfAppDb()
			return nil
		},
	})
	return client, nil
}

func Provide() fx.Option {
	return fx.Provide(
		fx.Annotate(
			util.NewPbConverter,
		),
		//cfAppDb client
		fx.Annotate(
			newCfAppDbPoolClient,
			fx.ResultTags(`name:"CfAppDbClient"`),
		),
		fx.Annotate(
			dbadapter.NewPoolAdapter,
			fx.ParamTags(``, `name:"CfAppDbClient"`), // first param is util.PbConverter have no tag name, the second one is name will be used in repository
			fx.ResultTags(`name:"CfAppDbAdapter"`),
		),
		// http out call generic
		fx.Annotate(
			NewHTTPCaller,
			fx.As(new(IHTTPCaller)),
		),
	)
}

