package adapter

import (
	"bytes"
	"context"
	"fmt"
	"io"
	"net/http"
	"time"

	"aps_los_vtiger/config"
	"aps_los_vtiger/internal/util"

	"github.com/pkg/errors"
	"go.uber.org/zap"
)

// IHTTPCaller sends outbound HTTP requests with pre-marshaled JSON body.
type IHTTPCaller interface {
	Call(ctx context.Context, destinationPath string, jsonBody []byte) (respBody []byte, err error)
}

type httpCaller struct {
	client *http.Client
	cfg    *config.Config
	logger *zap.Logger
}

func NewHTTPCaller(cfg *config.Config, logger *zap.Logger) IHTTPCaller {
	return &httpCaller{
		client: &http.Client{
			Timeout: time.Duration(cfg.RequestConfig.ReqTimeout) * time.Second,
			Transport: &http.Transport{
				MaxIdleConns:    30,
				MaxConnsPerHost: 50,
				IdleConnTimeout: 90 * time.Second,
			},
		},
		logger: logger,
		cfg:    cfg,
	}
}

func (h *httpCaller) Call(ctx context.Context, destinationPath string, jsonBody []byte) ([]byte, error) {
	var (
		url    string
		token  string
		method string
	)

	// get url and token from configs
	switch destinationPath {
	case "vtiger_cl":
		url = h.cfg.VtigerCL.URL
		token = h.cfg.VtigerCL.Token
		method = http.MethodPut
	case "pega_crm":
		url = h.cfg.PegaCRM.URL
		token = h.cfg.PegaCRM.Token
		method = http.MethodPut
	case "pega_crm_plntb":
		url = h.cfg.PegaCrmPLNTB.URL
		token = h.cfg.PegaCrmPLNTB.Token
		method = http.MethodPost
	case "vtiger_plntb":
		url = h.cfg.VtigerPLNTB.URL
		token = h.cfg.VtigerPLNTB.Token
		method = http.MethodPost
	case "vtiger_ntb":
		url = h.cfg.VtigerNTB.URL
		token = h.cfg.VtigerNTB.Token
		method = http.MethodPost
	default:
		secureToken := util.MaskString(token, 4)
		h.logger.Error(
			"Do not enough config to do http request",
			zap.String("URL", url),
			zap.String("Token", secureToken),
		)
		return nil, errors.New("unsupported destination path")
	}

	httpReq, err := http.NewRequestWithContext(ctx, method, url, bytes.NewReader(jsonBody))
	if err != nil {
		return nil, fmt.Errorf("create http request: %w", err)
	}
	httpReq.Header.Set("Content-Type", "application/json")
	httpReq.Header.Set("Authorization", "Basic "+token)

	resp, err := h.client.Do(httpReq)
	if err != nil {
		return nil, fmt.Errorf("http call to %s: %w", url, err)
	}
	defer resp.Body.Close()

	respBody, err := io.ReadAll(io.LimitReader(resp.Body, 1<<20)) // cap at 1MB
	if err != nil {
		return nil, fmt.Errorf("read response body from %s: %w", url, err)
	}

	if resp.StatusCode >= 400 {
		return respBody, fmt.Errorf("http call to %s returned status %s", url, resp.Status)
	}

	return respBody, nil
}

