package adapter

import (
	"context"
	"net/http"
	"net/http/httptest"
	"testing"

	"aps_los_vtiger/config"

	"go.uber.org/zap"
)

func testCfg(url, token string) *config.Config {
	cfg := &config.Config{}
	cfg.VtigerCL = config.DestConfig{URL: url, Token: token}
	cfg.RequestConfig.ReqTimeout = 5
	return cfg
}

func Test_Call_Success(t *testing.T) {
