package metric

import (
	"sync/atomic"
)

var (

	// ActiveGrpcCfAppDb is the total number of active sessions in FPS service for CfAppDb
	ActiveGrpcCfAppDb int64
)

// GetActiveGrpcCfAppDb returns the current value of active grpc connection to CfAppDb pool service
func GetActiveGrpcCfAppDb() int64 {
	return atomic.LoadInt64(&ActiveGrpcCfAppDb)
}

// SetActiveGrpcCfAppDb sets the value of active grpc connection to CfAppDb pool service
func SetActiveGrpcCfAppDb(value int64) {
	atomic.StoreInt64(&ActiveGrpcCfAppDb, value)
}

// IncrementActiveGrpcCfAppDb increments value of active grpc connection to CfAppDb pool service by 1.
func IncrementActiveGrpcCfAppDb() {
	atomic.AddInt64(&ActiveGrpcCfAppDb, 1)
}

// DecrementActiveGrpcCfAppDb decrements value of active grpc connection to CfAppDb pool service by 1.
func DecrementActiveGrpcCfAppDb() {
	atomic.AddInt64(&ActiveGrpcCfAppDb, -1)
}

