package common

// ParsedMessage is the common interface returned by every flow's XML parser.
// The pipeline uses it for filtering. The OutboundBuilder uses the concrete
// type underneath to construct the per-flow JSON request.
type ParsedMessage interface {
	GetCaseID() string              // vars.MainParams
	GetCRMID() string               // vars.MainParams
	GetStatusForSales() string      // vars.MainParams
	GetActionReqForSales() string   // vars.MainParams
	GetStage() string               // vars.MainParams
	GetStatus() string              // vars.MainParams
	GetAppID() string               // vars.MainParams
	GetPartnerIDUpper() string      // vars.MainParams
	GetOriginationAppUpper() string // vars.MainParams
	GetLeadID() string              // to log Kibana
	GetPosID() string               // vars.MainParams
	GetSource() string              // vars.MainParams
	GetLeadSource() string          // vars.MainParams
	GetIsProcess() bool             // some flow have condition to process message, if not satisfy, exit
	GetPath() string                // the path which request update status should go. It's key of `PathDestinationMap` map[string]string
}

// MessageParser parses raw XML bytes into a flow-specific ParsedMessage.
type MessageParser interface {
	Parse(raw []byte) (ParsedMessage, error)
}

// OutboundBuilder builds the per-flow JSON request body for a given reason.
// Returns pre-marshaled JSON bytes (use sonic.Marshal inside).
type OutboundBuilder interface {
	Build(msg ParsedMessage) ([]byte, error)
}

// FlowConfig defines the full processing config for one flow.
type FlowConfig struct {
	Name string
	// StatusStageFilter is the single filter for status + stage.
	//   - Key: allowed status
	//   - Value: nil → any stage passes; map[string]bool → only listed stages pass
	//   - Status not in map → rejected
	StatusStageFilter map[string]map[string]bool
	Parser            MessageParser
	Builder           OutboundBuilder
}

