package common

// ReasonCode represents reason code for DB logging
type ReasonCode string

const (
	ReasonSuccess       ReasonCode = "0"
	ReasonGeneralError  ReasonCode = "-1"
	ReasonDBError       ReasonCode = "-2"
	ReasonAdapterError  ReasonCode = "-4"
	ReasonFiltered      ReasonCode = "-10"
	ReasonHTTPCallError ReasonCode = "-11"
)

var reasonCodeValues = map[string]string{
	"0":   "Success",
	"-1":  "General Error",
	"-2":  "DB Error",
	"-4":  "Adapter Error",
	"-10": "Message Filtered",
	"-11": "HTTP Call Error",
}

func (rc ReasonCode) Code() string {
	return string(rc)
}

func (rc ReasonCode) Message() string {
	if value, ok := reasonCodeValues[rc.Code()]; ok {
		return value
	}
	return ""
}

