			LeadSource         string `xml:"LeadSource"`
			OriginationPartner string `xml:"OriginationPartner"`
			OriginationApp     string `xml:"OriginationApp"`
		} `xml:"OriginationDetails"`
		Status struct {
			Stage                    string `xml:"Stage"`
			Status                   string `xml:"Status"`
			DecisionReasonToSale     string `xml:"DecisionReasonToSale"`
			FinalUnderwritingComment string `xml:"FinalUnderwritingComment"`
			StatusForSales           string `xml:"StatusForSales"`
			ActionRequiredForSales   string `xml:"ActionRequiredForSales"`
			IssuedDateTime           string `xml:"IssuedDateTime"`
		} `xml:"Status"`
		LoanInfo struct {
			InterestRate        string `xml:"InterestRate"`
			OfferAmount         string `xml:"OfferAmount"`
			Tenure              string `xml:"Tenure"`
			ApproximateEMI      string `xml:"ApproximateEMI"`
			ApproximateEMI1     string `xml:"ApproximateEMI1"`
			AppropriateEMI2     string `xml:"AppropriateEMI2"`
			CashAmount          string `xml:"CashAmount"`
			InsuranceAmount     string `xml:"InsuranceAmount"`
			RetailLimit         string `xml:"RetailLimit"`
			AfterOverlapTenure  string `xml:"AfterOverlapTenure"`
			OverLapTenure       string `xml:"OverLapTenure"`
			InsuranceRate       string `xml:"InsuranceRate"`
			SelectedOfferTypeID string `xml:"SelectedOfferTypeID"` // IIB-8871
			MainCardType        string `xml:"MainCardType"`        // IIB-8871
		} `xml:"LoanInfo"`
		Disbursement struct {
			DisbursementType string `xml:"DisbursementType"`
		} `xml:"Disbursement"`
	} `xml:"StatusInfo"`
}

func (m *VtigerLosXml) GetCaseID() string         { return m.StatusInfo.CaseID }
func (m *VtigerLosXml) GetCRMID() string          { return m.StatusInfo.CRMID }
func (m *VtigerLosXml) GetStatusForSales() string { return m.StatusInfo.Status.StatusForSales }
func (m *VtigerLosXml) GetActionReqForSales() string {
	return m.StatusInfo.Status.ActionRequiredForSales
}
func (m *VtigerLosXml) GetStage() string  { return m.StatusInfo.Status.Stage }
func (m *VtigerLosXml) GetStatus() string { return m.StatusInfo.Status.Status }
func (m *VtigerLosXml) GetAppID() string  { return m.StatusInfo.AppID }
func (m *VtigerLosXml) GetPartnerIDUpper() string {
	return strings.ToUpper(m.StatusInfo.OriginationDetails.OriginationPartner)
}
func (m *VtigerLosXml) GetOriginationAppUpper() string {
	return strings.ToUpper(m.StatusInfo.OriginationDetails.OriginationApp)
}
func (m *VtigerLosXml) GetLeadID() string { return m.StatusInfo.LeadID }
func (m *VtigerLosXml) GetPosID() string {
	if m.GetPartnerIDUpper() == "PEGACRM" {
		return "PEGACRM"
	}
	return "VTCL"
}
func (m *VtigerLosXml) GetSource() string { return "PEGA_ULOS" }
func (m *VtigerLosXml) GetLeadSource() string {
	return strings.ToUpper(m.StatusInfo.OriginationDetails.LeadSource)
}
func (m *VtigerLosXml) GetIsProcess() bool {
	partner := []string{"VTIGER", "PEGACRM"}
	return (slices.Contains(partner, m.GetOriginationAppUpper()) ||
		slices.Contains(partner, m.GetPartnerIDUpper())) &&
		m.GetCRMID() != "" &&
		m.GetLeadSource() != "LEADDB"
}
func (m *VtigerLosXml) GetPath() string {
	if m.GetOriginationAppUpper() == "VTIGER" || m.GetPartnerIDUpper() == "VTIGER" {
		return "vtiger_cl"
	}
	if m.GetOriginationAppUpper() == "PEGACRM" || m.GetPartnerIDUpper() == "PEGACRM" {
		return "pega_crm"
	}
	return ""
}

// --- JSON outbound request ---
type VtigerLosOutbound struct {
	Crmid                 *string `json:"CRMID"`
	CaseID                *string `json:"CaseID"`
	LeadID                *string `json:"LeadID"`
	PartnerID             *string `json:"PartnerID"`
	PegaStage             *string `json:"PegaStage"`
	PegaStatus            *string `json:"PegaStatus"`
	OverlapTenor          *string `json:"OverlapTenor"`
