func Test_VtigerLosXml_GetIsProcess(t *testing.T) {
	tests := []struct {
		name           string
		originationApp string
		partnerID      string
		crmID          string
		leadSource     string
		want           bool
	}{
		{"VTIGER app with CRMID", "VTIGER", "", "CRM1", "OTHER", true},
		{"PEGACRM partner with CRMID", "", "PEGACRM", "CRM1", "OTHER", true},
		{"VTIGER but no CRMID", "VTIGER", "", "", "OTHER", false},
		{"VTIGER but LEADDB source", "VTIGER", "", "CRM1", "LEADDB", false},
		{"unknown partner", "OTHER", "OTHER", "CRM1", "X", false},
	}
	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			msg := &VtigerLosXml{}
			msg.StatusInfo.OriginationDetails.OriginationApp = tc.originationApp
			msg.StatusInfo.OriginationDetails.OriginationPartner = tc.partnerID
			msg.StatusInfo.CRMID = tc.crmID
			msg.StatusInfo.OriginationDetails.LeadSource = tc.leadSource
			if got := msg.GetIsProcess(); got != tc.want {
				t.Errorf("GetIsProcess() = %v, want %v", got, tc.want)
			}
		})
	}
}

