		name           string
		originationApp string
		partnerID      string
		want           string
	}{
		{"VTIGER app", "VTIGER", "", "vtiger_cl"},
		{"vtiger lowercase", "vtiger", "", "vtiger_cl"},
		{"PEGACRM app", "PEGACRM", "", "pega_crm"},
		{"PEGACRM partner", "", "PEGACRM", "pega_crm"},
		{"unknown", "OTHER", "OTHER", ""},
	}
	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			msg := &VtigerLosXml{}
			msg.StatusInfo.OriginationDetails.OriginationApp = tc.originationApp
			msg.StatusInfo.OriginationDetails.OriginationPartner = tc.partnerID
			if got := msg.GetPath(); got != tc.want {
				t.Errorf("GetPath() = %q, want %q", got, tc.want)
			}
		})
	}
}

func Test_VtigerLosXml_ParseFromXML(t *testing.T) {
	xmlData := `<StatusUpdatedMessage xmlns:ns1="http://example.com">
		<StatusInfo>
			<AppID>APP123</AppID>
			<CaseID>CASE456</CaseID>
			<CRMID>CRM789</CRMID>
			<LeadID>LEAD1</LeadID>
			<OriginationDetails>
				<OriginationApp>VTIGER</OriginationApp>
				<OriginationPartner>VTIGER</OriginationPartner>
				<LeadSource>DIRECT</LeadSource>
			</OriginationDetails>
			<Status>
				<Stage>Initiation</Stage>
				<Status>New</Status>
			</Status>
		</StatusInfo>
	</StatusUpdatedMessage>`

	var msg VtigerLosXml
	if err := xml.Unmarshal([]byte(xmlData), &msg); err != nil {
		t.Fatalf("unmarshal failed: %v", err)
	}
	if msg.GetAppID() != "APP123" {
		t.Errorf("AppID = %q", msg.GetAppID())
	}
	if msg.GetCRMID() != "CRM789" {
		t.Errorf("CRMID = %q", msg.GetCRMID())
	}
	if !msg.GetIsProcess() {
		t.Error("expected IsProcess=true")
	}
	if msg.GetPath() != "vtiger_cl" {
		t.Errorf("Path = %q", msg.GetPath())
	}
}

