func Test_vtigerLosLos3Parser_Parse_ValidXML(t *testing.T) {
	xml := `<ApplicationUpdatedMessage xmlns:ns1="http://example.com">
		<LOSApplication>
			<AppID>APP2</AppID>
			<CaseID>CASE2</CaseID>
			<Status><Stage>Init</Stage><Status>New</Status></Status>
			<Sales><LeadID>LEAD2</LeadID></Sales>
			<Loan><OriginationDetails><OriginationApp>VTIGER</OriginationApp></OriginationDetails></Loan>
			<Partner><PartnerID>VTIGER</PartnerID></Partner>
			<Underwriting><Offer></Offer></Underwriting>
