)

type vtigerLosLos3Parser struct{}

func (p *vtigerLosLos3Parser) Parse(raw []byte) (common.ParsedMessage, error) {
	var msg dto.VtigerLosLos3Xml
	if err := xml.Unmarshal(raw, &msg); err != nil {
		return nil, fmt.Errorf("parse vtigerLosLos3 xml: %w", err)
	}
	return &msg, nil
}

type vtigerLosLos3Builder struct{}

func (b *vtigerLosLos3Builder) Build(msg common.ParsedMessage) ([]byte, error) {
	m, ok := msg.(*dto.VtigerLosLos3Xml)
	if !ok {
		return nil, fmt.Errorf("unexpected message type for vtigerLosLos3 builder")
	}

	if m.GetOriginationAppUpper() == "VTIGER" {
		crmID := m.GetCRMID()
		return sonic.Marshal(dto.VtigerLosLos3Outbound{
			CaseID:              util.StrToPtr(m.LOSApplication.CaseID),
			Crmid:               util.StrToPtr(crmID),
			StatusForSales:      util.StrToPtr(m.LOSApplication.Status.StatusForSales),
			ActionReqForSales:   util.StrToPtr(m.LOSApplication.Status.ActionReqForSales),
			LastStatusPega:      util.StrToPtr(m.LOSApplication.Status.Status),
			LastStagePega:       util.StrToPtr(m.LOSApplication.Status.Stage),
			FinalApprovedAmount: util.StrToPtr(m.LOSApplication.Underwriting.Offer.OfferAmountLoan),
			FinalTenor:          util.IntToPtr(m.LOSApplication.Loan.FinalTenor),
			SalesReason:         util.StrToPtr(m.LOSApplication.RejectApplication.Result.ReasonFeedbackToSales),
			OverlapTenor:        util.IntToPtr(m.LOSApplication.Loan.OverlapTenor),
			PostOverlapTenor:    util.IntToPtr(m.LOSApplication.Loan.FinalTenorAfterOverlap),
			AppID:               util.StrToPtr(m.LOSApplication.AppID),
		})
	}

	if m.GetPartnerIDUpper() == "VTIGER" {
		var finalApprovedAmount *string
		var finalTenor *int
		if m.LOSApplication.Status.Stage == "DocumentCollection" &&
			m.LOSApplication.Status.Status == "Pending-DocCollect-CustomerESign" {
			finalApprovedAmount = util.StrToPtr(m.LOSApplication.Underwriting.Offer.OfferAmountLoan)
			finalTenor = util.IntToPtr(m.LOSApplication.Loan.FinalTenor)
		}

		return sonic.Marshal(dto.VtigerLosLos3PartnerOutbound{
			Crmid:               util.StrToPtr(m.LOSApplication.Sales.LeadID),
			PegaStatus:          util.StrToPtr(m.LOSApplication.Status.Status),
			PegaStage:           util.StrToPtr(m.LOSApplication.Status.Stage),
			OverlapTenor:        util.IntToPtr(m.LOSApplication.Loan.OverlapTenor),
			PostOverlapTenor:    util.IntToPtr(m.LOSApplication.Loan.FinalTenorAfterOverlap),
			CaseID:              util.StrToPtr(m.LOSApplication.CaseID),
			FinalApprovedAmount: finalApprovedAmount,
			FinalTenor:          finalTenor,
			SalesReason:         util.StrToPtr(m.LOSApplication.RejectApplication.Result.ReasonFeedbackToSales),
			AppID:               util.StrToPtr(m.LOSApplication.AppID),
		})
	}

	return nil, errors.ErrUnsupported
}

