	var msg dto.VymoVtigerLos3XML
	if err := xml.Unmarshal(raw, &msg); err != nil {
		return nil, fmt.Errorf("parse vymoVtigerLos3 xml: %w", err)
	}
	return &msg, nil
}

type vymoVtigerLos3Builder struct{}

func (b *vymoVtigerLos3Builder) Build(msg common.ParsedMessage) ([]byte, error) {
	m, ok := msg.(*dto.VymoVtigerLos3XML)
	if !ok {
		return nil, fmt.Errorf("unexpected message type for vymoVtigerLos3 builder")
	}

	var pendingRejectreasons *string
	if m.LOSApplication.Status.Status != "Resolved-Rejected-Hard" {
		combine := m.LOSApplication.Underwriting.FUW.PHV.Result.Comment + ". " + m.LOSApplication.ReworkHistory.ReworkHistory.ReworkDescription
		pendingRejectreasons = util.StrToPtr(combine)
	}

	var appCreatedDate *string
	if len(m.LOSApplication.Status.CreatedTime) >= 10 {
		slice := m.LOSApplication.Status.CreatedTime[0:10]
		appCreatedDate = &slice
	}

	var saleCompanyName string
	if m.LOSApplication.Customer.WorkDetails.Company.TaxCode != "" &&
		m.LOSApplication.Customer.WorkDetails.Company.TaxCode != "NA" {
		saleCompanyName = m.LOSApplication.Customer.WorkDetails.Company.Name
	} else {
		saleCompanyName = m.LOSApplication.Customer.WorkDetails.Company.SaleCompName
	}

	var productName string
	if m.LOSApplication.Loan.Product != nil {
		productName = m.LOSApplication.Loan.Product.Name
	}

	return sonic.Marshal(&dto.VymoVtigerLos3Outbound{
		Crmid:                 util.StrToPtr(m.LOSApplication.Sales.LeadID),
		PendingRejectreasons:  pendingRejectreasons,
		AppCreatedDate:        appCreatedDate,
		ContractNo:            util.StrToPtr(m.LOSApplication.ContractNo),
		Insurance:             util.StrToPtr(m.LOSApplication.Loan.InsuranceAmount),
		Emi:                   util.StrToPtr(m.LOSApplication.Underwriting.Offer.EMI),
