		LoanEMI:               util.StrToPtr(m.LOSApplication.Loan.LoanEMI),
		FirstRegistrationDate: util.StrToPtr(m.LOSApplication.Loan.BikeInformation.FirstRegistrationDate),
		SaleCompanyName:       util.StrToPtr(saleCompanyName),
		NetIncome:             util.StrToPtr(m.LOSApplication.Customer.IncomeLiability.Income.Amount),
		ProductScheme:         util.StrToPtr(productName),
		OfferAmount:           util.StrToPtr(m.LOSApplication.Underwriting.Offer.OfferAmountLoan),
		TotalOfferAmount:      util.StrToPtr(m.LOSApplication.Underwriting.Offer.TotalCreditAmount),
		RequestedAmount:       util.StrToPtr(m.LOSApplication.Loan.RequestedAmount),
		RequestedTenure:       util.StrToPtr(m.LOSApplication.Loan.RequestedTenure),
