package flow

import (
	"aps_los_vtiger/internal/common"
	"testing"
)

func Test_Registry_AllFlowsRegistered(t *testing.T) {
	reg := Registry()

	expectedFlows := []string{
		common.FlowVtigerLos,
		common.FlowVymoVtiger,
		common.FlowVtigerLosLOS3,
		common.FlowVymoVtigerLOS3,
	}

	for _, name := range expectedFlows {
		fc, ok := reg[name]
		if !ok {
			t.Errorf("flow %q not found in registry", name)
			continue
		}
		if fc.Name != name {
			t.Errorf("flow %q has Name=%q", name, fc.Name)
		}
		if fc.Parser == nil {
			t.Errorf("flow %q has nil Parser", name)
		}
		if fc.Builder == nil {
			t.Errorf("flow %q has nil Builder", name)
		}
		if fc.StatusStageFilter == nil {
			t.Errorf("flow %q has nil StatusStageFilter", name)
		}
		if len(fc.StatusStageFilter) == 0 {
			t.Errorf("flow %q has empty StatusStageFilter", name)
		}
	}
}

func Test_Registry_StatusStageFilter_NilMeansAnyStage(t *testing.T) {
	reg := Registry()

	// FlowVtigerLos has all nil stages (any stage allowed)
	fc := reg[common.FlowVtigerLos]
	for status, stages := range fc.StatusStageFilter {
		if stages != nil {
			t.Errorf("FlowVtigerLos status %q has non-nil stages, expected nil (any stage)", status)
		}
	}
}

func Test_Registry_StatusStageFilter_LOS3HasStageRestrictions(t *testing.T) {
	reg := Registry()

	fc := reg[common.FlowVtigerLosLOS3]

	// "New" should only allow "Initiation"
	stages, ok := fc.StatusStageFilter["New"]
	if !ok {
		t.Fatal("status 'New' not in FlowVtigerLosLOS3")
	}
	if stages == nil {
		t.Fatal("status 'New' should have stage restrictions")
	}
	if !stages["Initiation"] {
		t.Error("status 'New' should allow stage 'Initiation'")
	}
	if stages["Disbursement"] {
		t.Error("status 'New' should NOT allow stage 'Disbursement'")
	}
}

func Test_Registry_StatusStageFilter_VymoLOS3HasStageRestrictions(t *testing.T) {
	reg := Registry()

	fc := reg[common.FlowVymoVtigerLOS3]

	// "Pending-DC" should only allow "DataCheck"
	stages, ok := fc.StatusStageFilter["Pending-DC"]
	if !ok {
		t.Fatal("status 'Pending-DC' not in FlowVymoVtigerLOS3")
	}
	if stages == nil {
		t.Fatal("status 'Pending-DC' should have stage restrictions")
	}
	if !stages["DataCheck"] {
		t.Error("status 'Pending-DC' should allow stage 'DataCheck'")
	}

	// "Resolved-Rejected-Soft" should allow multiple stages
	stages, ok = fc.StatusStageFilter["Resolved-Rejected-Soft"]
	if !ok {
		t.Fatal("status 'Resolved-Rejected-Soft' not in FlowVymoVtigerLOS3")
	}
	if stages == nil {
		t.Fatal("should have stage restrictions")
	}
	if len(stages) < 5 {
		t.Errorf("Resolved-Rejected-Soft should have many stages, got %d", len(stages))
	}
}

func Test_Registry_FlowCount(t *testing.T) {
	reg := Registry()
	if len(reg) != 4 {
		t.Errorf("expected 4 flows, got %d", len(reg))
	}
}

package repository

import (
	"context"
	"fmt"
	"strconv"
	"time"

	"aps_los_vtiger/config"
	"aps_los_vtiger/internal/dto"

	adapter "esb-go-libs/dbadapter"
	"esb-go-libs/dbadapter/model"

	"github.com/google/uuid"
	"go.uber.org/fx"
	"go.uber.org/zap"
)

const insertLogQuery = `INSERT INTO APP_DOMINO.IIB_POS_SUBSCRIBER_LOG 
(LOGID, APPID, POSID, SOURCE, MESSAGE, RESULT_STATUS, RESULT_MESSAGE) 
VALUES (:p_logID, :p_appID, :p_posID, :p_source, :p_message, :p_resultStatus, :p_resultMessage)`

// IProcessingLogRepository writes processing logs to DB.
type IProcessingLogRepository interface {
	InsertLog(ctx context.Context, log dto.ProcessingLog) error
}

type processingLogRepository struct {
	cfg            *config.Config
	logger         *zap.Logger
	cfAppDbAdapter adapter.IPoolAPIAdapter
}

func NewProcessingLogRepository(
	cfg *config.Config,
	logger *zap.Logger,
	params struct {
		fx.In

		CfAppDbAdapter adapter.IPoolAPIAdapter `name:"CfAppDbAdapter"`
	},
) IProcessingLogRepository {
	return &processingLogRepository{
		cfg:            cfg,
		logger:         logger,
		cfAppDbAdapter: params.CfAppDbAdapter,
	}
}

func (r *processingLogRepository) InsertLog(ctx context.Context, log dto.ProcessingLog) error {
	logID, err := uuid.NewV7() // use V7 for optimize storage space in db
	if err != nil {
		return fmt.Errorf("generate uuidV7: %w", err)
	}

	req := &model.PoolServiceRequest{
		Sys: model.SysReq{
			TransID:     log.TransID,
			RequestorID: "aps-los-vtiger",
			DateTime:    time.Now().Format(time.RFC3339Nano),
		},
		QueryString: insertLogQuery,
		InputParameters: []model.QueryParam{
			{Name: "p_logID", Value: logID.String(), DataType: "VARCHAR2"},
			{Name: "p_appID", Value: log.AppID, DataType: "VARCHAR2"},
			{Name: "p_posID", Value: log.PosID, DataType: "VARCHAR2"},
			{Name: "p_source", Value: log.Source, DataType: "VARCHAR2"},
			{Name: "p_message", Value: log.RequestBody, DataType: "CLOB"},
			{Name: "p_resultStatus", Value: strconv.Itoa(log.ResultStatus), DataType: "VARCHAR2"},
			{Name: "p_resultMessage", Value: log.ResponseBody, DataType: "CLOB"},
		},
	}

	_, err = r.cfAppDbAdapter.PoolExecuteQuery(ctx, req, r.cfg.CfAppDbClient.Username, r.cfg.CfAppDbClient.Password)
	if err != nil {
		r.logger.Error("InsertLog failed",
			zap.String("TransID", log.TransID),
			zap.String("AppID", log.AppID),
			zap.String("ErrMsg", err.Error()),
		)
		return fmt.Errorf("insert log: %w", err)
	}

	r.logger.Info("InsertLog success",
		zap.String("LogID", logID.String()),
		zap.String("AppID", log.AppID),
		zap.String("TransID", log.TransID),
	)
	return nil
}

