package subscriber

import (
	"context"

	"aps_los_vtiger/config"
	"aps_los_vtiger/internal/common"
	"aps_los_vtiger/internal/helper"
	flow "aps_los_vtiger/internal/parser"
	"aps_los_vtiger/internal/usecase"

	"esb-go-libs/activemq"
	"esb-go-libs/activemq/domain"

	"go.uber.org/fx"
	"go.uber.org/zap"
)

// subscribedQueue tracks a subscription for cleanup on shutdown.
// Receiver points to the same client that owns this subscription so
// Unsubscribe goes back to the right one.
type subscribedQueue struct {
	MsgType     domain.MessageType
	Destination string
	Receiver    *activemq.Receiver
}

type Subscriber struct {
	cfg          *config.Config
	logger       *zap.Logger
	usecase      usecase.IMessageUsecase
	losReceiver  *helper.LosReceiver  // serves vtiger_los, vymo_vtiger
	los3Receiver *helper.Los3Receiver // serves vtiger_los_los3, vymo_vtiger_los3
	registry     map[string]common.FlowConfig
	subscribed   []subscribedQueue
}

func NewSubscriber(
	cfg *config.Config,
	logger *zap.Logger,
	uc usecase.IMessageUsecase,
	losReceiver *helper.LosReceiver,
	los3Receiver *helper.Los3Receiver,
) *Subscriber {
	return &Subscriber{
		cfg:          cfg,
		logger:       logger,
		usecase:      uc,
		losReceiver:  losReceiver,
		los3Receiver: los3Receiver,
		registry:     flow.Registry(),
	}
}

func Provide() fx.Option {
	return fx.Provide(NewSubscriber)
}

// receiverForFlow picks the right receiver based on the flow name.
// LOS group: vtiger_los, vymo_vtiger
// LOS3 group: vtiger_los_los3, vymo_vtiger_los3
func (s *Subscriber) receiverForFlow(flowName string) *activemq.Receiver {
	switch flowName {
	case common.FlowVtigerLos, common.FlowVymoVtiger:
		return s.losReceiver.Receiver
	case common.FlowVtigerLosLOS3, common.FlowVymoVtigerLOS3:
		return s.los3Receiver.Receiver
	}
	return nil
}

func Start(lc fx.Lifecycle, s *Subscriber) {
	// Use a background context for subscriptions — fx startup ctx has a short timeout
	subCtx, subCancel := context.WithCancel(context.Background())

	lc.Append(fx.Hook{
		OnStart: func(ctx context.Context) error {
			s.logger.Info("Starting ActiveMQ subscribers...")
			for flowName, qCfg := range s.cfg.Queues {
				fc, ok := s.registry[flowName]
				if !ok {
					s.logger.Error("No FlowConfig registered; skipping queue",
						zap.String("FlowName", flowName),
						zap.String("Destination", qCfg.Destination),
					)
					continue
				}
				receiver := s.receiverForFlow(flowName)
				if receiver == nil {
					s.logger.Error("No receiver mapped for flow; skipping queue",
						zap.String("FlowName", flowName),
						zap.String("Destination", qCfg.Destination),
					)
					continue
				}
				s.subscribe(subCtx, fc, qCfg, receiver)
			}
			return nil
		},
		OnStop: func(ctx context.Context) error {
			s.logger.Info("Cancelling subscription context...")
			subCancel()
			s.logger.Info("Unsubscribing all ActiveMQ queues...")
			for _, sq := range s.subscribed {
				if err := sq.Receiver.Unsubscribe(sq.MsgType, sq.Destination); err != nil {
					s.logger.Error("Failed to unsubscribe",
						zap.String("Destination", sq.Destination),
						zap.String("ErrMsg", err.Error()),
					)
				} else {
					s.logger.Info("Unsubscribed",
						zap.String("Destination", sq.Destination),
					)
				}
			}
			s.logger.Info("Waiting for pending log writes...")
			s.usecase.WaitPendingLogs()
			return nil
		},
	})
}

func (s *Subscriber) subscribe(ctx context.Context, fc common.FlowConfig, qCfg config.QueueCfg, receiver *activemq.Receiver) {
	msgType := domain.MessageType(qCfg.MsgType)

	workers := qCfg.Workers
	if workers <= 0 {
		workers = 1
	}

	handler := func(ctx context.Context, msg domain.MessageReceived) error {
		return s.usecase.HandleMessage(ctx, fc, msg.Message.Payload, msg.Message.Headers)
	}

	retryOpts := &domain.RetryOption{
		UseRetry:           true,
		InitialInterval:    5,
		MaxIntervalBackOff: 30,
		Multiplier:         1.5,
		MaxAttemp:          0,
		MaxElapsedTime:     0,
	}

	for i := 0; i < workers; i++ {
		subsCfg := &domain.SubscriberConfig{
			AppName:      s.cfg.ActiveMQ.AppName,
			Destination:  qCfg.Destination,
			MsgType:      msgType,
			Durable:      qCfg.Durable,
			ACKMode:      domain.AckMode(qCfg.ACKMode),
			PrefetchSize: qCfg.PrefetchSize,
			WorkerSize:   qCfg.WorkersHandler,
		}

		if err := receiver.Subscribe(ctx, handler, subsCfg, retryOpts); err != nil {
			s.logger.Error("Failed to subscribe worker",
				zap.String("FlowName", fc.Name),
				zap.String("Destination", qCfg.Destination),
				zap.Int("WorkerNum", i+1),
				zap.String("ErrMsg", err.Error()),
			)
			continue
		}

		s.logger.Info("Subscribed worker",
			zap.String("FlowName", fc.Name),
			zap.String("Destination", qCfg.Destination),
			zap.Int("WorkerNum", i+1),
			zap.Int("TotalWorkers", workers),
		)
	}

	s.subscribed = append(s.subscribed, subscribedQueue{
		MsgType:     msgType,
		Destination: qCfg.Destination,
		Receiver:    receiver,
	})
}

