package usecase

import (
	"context"
	"errors"
	"fmt"
	"sync"
	"time"

	"aps_los_vtiger/config"
	"aps_los_vtiger/internal/adapter"
	"aps_los_vtiger/internal/common"
	"aps_los_vtiger/internal/dto"
	"aps_los_vtiger/internal/repository"
	"aps_los_vtiger/internal/util"

	"go.uber.org/zap"
)

// IMessageUsecase processes incoming queue messages for any flow.
type IMessageUsecase interface {
	HandleMessage(ctx context.Context, flow common.FlowConfig, raw []byte, headers map[string]string) error
	WaitPendingLogs()
}

type messageUsecase struct {
	cfg    *config.Config
	logger *zap.Logger
	repo   repository.IProcessingLogRepository
	caller adapter.IHTTPCaller
	wg     sync.WaitGroup
}

func NewMessageUsecase(
	cfg *config.Config,
	logger *zap.Logger,
	repo repository.IProcessingLogRepository,
	caller adapter.IHTTPCaller,
) IMessageUsecase {
	return &messageUsecase{
		cfg:    cfg,
		logger: logger,
		repo:   repo,
		caller: caller,
	}
}

// HandleMessage is the shared pipeline for all flows:
//  1. Filter by status + stage — if not matched, return immediately
//  2. Parse raw XML via flow.Parser (each flow has different XML structure)
//  3. Filter reasons — if no valid reasons, return immediately
//  4. For each valid reason: build JSON via flow.Builder, call HTTP
//  5. Write log to DB (success or error)
func (uc *messageUsecase) HandleMessage(ctx context.Context, flow common.FlowConfig, raw []byte, headers map[string]string) error {
	var (
		correlationID = headers["correlation-id"]
	)
	// capture correlation-id from header, if nil, generate one
	if correlationID == "" {
		correlationID = util.GenCorrelationID()
	}
	// --- 1. First filter: status + stage ---
	status := headers["Status"]
	stage := headers["Stage"]
	stages, statusAllowed := flow.StatusStageFilter[status]
	if !statusAllowed {
		return nil // status not in map -> reject
	}
	if stages != nil && !stages[stage] {
		return nil // status has stage restriction, stage doesn't match → reject
	}
	// --- 2. Parse XML (flow-specific) ---
	msg, err := flow.Parser.Parse(raw)
	if err != nil {
		uc.logger.Error(
			"Failed to parse message",
			zap.String("FlowName", flow.Name),
			zap.String("TransID", correlationID),
			zap.String("ErrMsg", err.Error()),
		)
		uc.writeLog(dto.ProcessingLog{
			FlowName:     flow.Name,
			TransID:      correlationID,
			Source:       flow.Name,
			RequestBody:  string(raw),
			ResultStatus: 0,
			ResponseBody: fmt.Sprintf("parse error: %v", err),
		})
		return fmt.Errorf("parse message: %w", err)
	}

	if !msg.GetIsProcess() {
		return nil // exit now
	}

	uc.logger.Info(
		"Processing message",
		zap.String("FlowName", flow.Name),
		zap.String("AppID", msg.GetAppID()),
		zap.String("Status", status),
		zap.String("Stage", stage),
		zap.String("TransID", correlationID),
	)

	// --- 3. Second filter partner to call VTIGER or PEGACRM ---
	// get destination of request update status application
	pathDestination := msg.GetPath()
	if pathDestination == "" {
		return nil // exit now
	}

	outBody, err := flow.Builder.Build(msg)
	if err != nil && errors.Is(err, errors.ErrUnsupported) {
		return nil // exit, not process anymore
	}
	if err != nil {
		uc.logger.Error("Failed to build outbound request",
			zap.String("FlowName", flow.Name),
			zap.String("AppID", msg.GetAppID()),
			zap.String("ErrMsg", err.Error()),
			zap.String("PathDestination", pathDestination),
			zap.String("TransID", correlationID),
		)
		uc.writeLog(dto.ProcessingLog{
			FlowName:     flow.Name,
			TransID:      correlationID,
			AppID:        msg.GetAppID(),
			PosID:        msg.GetPosID(),
			Source:       msg.GetSource(),
			ResultStatus: 0,
			ResponseBody: fmt.Sprintf("failed to build outbound request: %v", err),
		})
		return err
	}

	// log request body like Mulesoft
	uc.logger.Info(
		"Request Body",
		zap.ByteString("RequestBodyStr", outBody),
		zap.String("FlowName", flow.Name),
		zap.String("AppID", msg.GetAppID()),
		zap.String("PathDestination", pathDestination),
		zap.String("TransID", correlationID),
	)

	// do call to path destination
	respBody, err := uc.caller.Call(ctx, pathDestination, outBody)
	if err != nil {
		uc.logger.Error("HTTP call failed",
			zap.String("FlowName", flow.Name),
			zap.String("ResponseBody", string(respBody)),
			zap.String("TransID", correlationID),
			zap.String("PathDestination", pathDestination),
			zap.String("ErrMsg", err.Error()),
		)
		uc.writeLog(dto.ProcessingLog{
			FlowName:     flow.Name,
			TransID:      correlationID,
			AppID:        msg.GetAppID(),
			PosID:        msg.GetPosID(),
			Source:       msg.GetSource(),
			RequestBody:  string(outBody),
			ResultStatus: 0,
			ResponseBody: err.Error(),
		})
		return err
	}

	// log response body like Mulesoft
	uc.logger.Info(
		"Response Body",
		zap.ByteString("ResponseBodyStr", respBody),
		zap.String("FlowName", flow.Name),
		zap.String("AppID", msg.GetAppID()),
		zap.String("PathDestination", pathDestination),
		zap.String("TransID", correlationID),
	)

	// --- 5. Write log ---
	uc.writeLog(dto.ProcessingLog{
		FlowName:     flow.Name,
		TransID:      correlationID,
		AppID:        msg.GetAppID(),
		PosID:        msg.GetPosID(),
		Source:       msg.GetSource(),
		RequestBody:  string(outBody),
		ResultStatus: util.ParseResultStatus(respBody),
		ResponseBody: string(respBody),
	})

	return nil
}

func (uc *messageUsecase) writeLog(log dto.ProcessingLog) {
	uc.wg.Add(1)
	go func() {
		defer uc.wg.Done()
		ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
		defer cancel()
		if err := uc.repo.InsertLog(ctx, log); err != nil {
			uc.logger.Error("Failed to write log to DB",
				zap.String("FlowName", log.FlowName),
				zap.String("AppID", log.AppID),
				zap.String("TransID", log.TransID),
				zap.String("ErrMsg", err.Error()),
			)
		}
	}()
}

// WaitPendingLogs blocks until all in-flight log writes complete.
func (uc *messageUsecase) WaitPendingLogs() {
	uc.wg.Wait()
}

