package util

import (
	"fmt"
	"strconv"
	"strings"
	"time"

	"github.com/google/uuid"
	"go.uber.org/zap"
)

func GenCorrelationID() string {
	id, _ := uuid.NewV7()
	return id.String()
}

func ConvertStrToInt8(input string) int8 {
	result, err := strconv.ParseInt(input, 10, 8)
	if err == nil {
		return int8(result)
	}
	return 0
}

func ConvertStrToInt32(input string) int32 {
	result, err := strconv.ParseInt(input, 10, 32)
	if err == nil {
		return int32(result)
	}
	return 0
}

func NVL[T comparable](value *T, defaultValue T) T {
	if value == nil {
		return defaultValue
	}
	return *value
}

// ConvertDateTime parses a date-time string pointer in either "20060102T150405.000 MST"
// or RFC3339Nano format and returns a pointer to the date formatted as "2006-01-02".
// Returns a pointer to an empty string if input is nil, empty, or cannot be parsed.
func ConvertDateTime(input *string) *string {
	result := ""
	if input == nil || *input == "" {
		return &result
	}
	// try parse 20060102T150405.000 MST format
	t, err := time.Parse("20060102T150405.000 MST", *input)
	if err != nil {
		// try format RFC3339: 2026-05-04T16:10:19.360Z
		var errTry error
		t, errTry = time.Parse(time.RFC3339Nano, *input)
		if errTry != nil {
			zap.L().Error(
				fmt.Sprintf("Can not parse date time format %v to yyyy-mm-dd", *input),
			)
			return &result
		}
	}
	result = t.Format("2006-01-02")
	return &result
}

// ConvStrToPInt converts a string to a pointer to int.
// Returns a pointer to 0 if the input is empty or cannot be parsed.
func ConvStrToPInt(input string) *int {
	var result int
	if input == "" {
		return &result
	}
	// Convert string to int
	val, err := strconv.Atoi(input)
	if err != nil {
		return &result
	}
	return &val
}

// ParseResultStatus checks response body JSON for "success":true or "Success":true.
// Returns 1 if found, 0 otherwise.
func ParseResultStatus(respBody []byte) int {
	body := string(respBody)
	if strings.Contains(body, `"success":true`) || strings.Contains(body, `"Success":true`) ||
		strings.Contains(body, `"success": true`) || strings.Contains(body, `"Success": true`) {
		return 1
	}
	return 0
}

// MaskString masks a string showing only the last n characters.
// e.g. MaskString("abcdefgh", 4) → "****efgh"
func MaskString(s string, showLast int) string {
	if len(s) <= showLast {
		return s
	}
	return strings.Repeat("*", len(s)-showLast) + s[len(s)-showLast:]
}

// StrToPtr converts a string to *string. Returns nil if empty (-> null in JSON).
func StrToPtr(s string) *string {
	if s == "" {
		return nil
	}
	return &s
}

// IntToPtr converts an int to *int. Returns nil if zero (-> null in JSON).
func IntToPtr(i int) *int {
	if i == 0 {
		return nil
	}
	return &i
}

