func Test_ConvertStrToInt8(t *testing.T) {
	tests := []struct {
		name  string
		input string
		want  int8
	}{
		{"valid positive", "42", 42},
		{"valid negative", "-10", -10},
		{"zero", "0", 0},
		{"max int8", "127", 127},
		{"min int8", "-128", -128},
		{"overflow", "200", 0},
		{"empty string", "", 0},
		{"non-numeric", "abc", 0},
	}
	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			got := ConvertStrToInt8(tc.input)
			if got != tc.want {
				t.Errorf("ConvertStrToInt8(%q) = %d, want %d", tc.input, got, tc.want)
			}
		})
	}
}

