func Test_NVL(t *testing.T) {
	t.Run("nil pointer returns default", func(t *testing.T) {
		got := NVL[string](nil, "default")
		if got != "default" {
			t.Errorf("NVL(nil, default) = %q, want %q", got, "default")
		}
	})
	t.Run("non-nil pointer returns value", func(t *testing.T) {
		val := "hello"
		got := NVL(&val, "default")
		if got != "hello" {
			t.Errorf("NVL(&hello, default) = %q, want %q", got, "hello")
		}
	})
	t.Run("empty string pointer returns empty", func(t *testing.T) {
		val := ""
		got := NVL(&val, "default")
		if got != "" {
			t.Errorf("NVL(&empty, default) = %q, want %q", got, "")
		}
	})
}

