func strPtr(s string) *string { return &s }

func Test_StrToPtr(t *testing.T) {
	tests := []struct {
		name    string
		input   string
		wantNil bool
		want    string
	}{
		{"empty returns nil", "", true, ""},
		{"non-empty returns pointer", "hello", false, "hello"},
		{"whitespace is not empty", " ", false, " "},
		{"long string", "abcdefghijklmnopqrstuvwxyz", false, "abcdefghijklmnopqrstuvwxyz"},
	}
	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			got := StrToPtr(tc.input)
			if tc.wantNil {
				if got != nil {
					t.Errorf("StrToPtr(%q) = %q, want nil", tc.input, *got)
				}
			} else {
				if got == nil {
					t.Fatalf("StrToPtr(%q) = nil, want %q", tc.input, tc.want)
				}
				if *got != tc.want {
					t.Errorf("StrToPtr(%q) = %q, want %q", tc.input, *got, tc.want)
				}
			}
		})
	}
}

